// Combine results from all agents
const bielData = $('Biel Strategic Analysis').first().json;
const brunoData = $('Bruno Documentation').first().json;
const martinhoData = $('Martinho Security Check').first().json;

const result = {
  colmeiaSession: {
    id: `basic_${Date.now()}`,
    timestamp: new Date().toISOString(),
    protocol: 'standard',
    agents: ['biel', 'bruno', 'martinho']
  },

  strategicAnalysis: {
    summary: bielData.summary,
    insights: bielData.insights || [],
    recommendations: bielData.recommendations || []
  },

  documentation: {
    structure: brunoData.document || brunoData.organizationalSummary,
    notionUpdates: brunoData.notionPages || [],
    kanban: brunoData.kanbanUpdate || null
  },

  security: {
    status: martinhoData.complianceStatus,
    score: martinhoData.securityAudit?.score || 0,
    findings: martinhoData.securityAudit?.findings || [],
    recommendations: martinhoData.securityAudit?.recommendations || []
  },

  overallAssessment: {
    readiness: martinhoData.complianceStatus === 'PASSED' ? 'approved' : 'review_required',
    confidence: 'high',
    nextSteps: [
      'Review strategic recommendations',
      'Implement documentation structure',
      'Address any security concerns'
    ]
  }
};

return [{ json: result }];
